#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <time.h>
#include <openssl/sha.h>

// Maximum size definitions
#define HASH_SIZE 65 // SHA-256 produces 32 bytes = 64 hex chars + null
#define MAX_TRANSACTIONS 10

// Transaction structure
typedef struct {
 char sender[50];
 char recipient[50];
 double amount;
} Transaction;

// Block structure - contains all generic block elements
typedef struct Block {
 int index; // Block number
 time_t timestamp; // When block was created
 Transaction transactions[MAX_TRANSACTIONS]; // List of transactions
 int transaction_count;
 char previous_hash[HASH_SIZE]; // Hash of previous block
 char hash[HASH_SIZE]; // Current block's hash
 unsigned int nonce; // For proof-of-work
 struct Block* next; // Pointer to next block
} Block;

// Blockchain structure - represents the distributed ledger
typedef struct {
 Block* genesis_block;
 Block* last_block;
 int difficulty; // Mining difficulty
} Blockchain;

// Function to convert binary hash to hexadecimal string
void bytesToHex(const unsigned char* bytes, char* hexString) {
 for (int i = 0; i < SHA256_DIGEST_LENGTH; i++) {
 sprintf(hexString + (i * 2), "%02x", bytes[i]);
 }
 hexString[64] = '\0';
}

// Calculate SHA-256 hash of block data
void calculate_block_hash(Block* block, char* output_hash) {
 // Create string representation of block data
 char data[1024] = {0};
 char temp[100];

 sprintf(temp, "%d", block->index);
 strcat(data, temp);

 sprintf(temp, "%ld", block->timestamp);
 strcat(data, temp);

 strcat(data, block->previous_hash);

 sprintf(temp, "%u", block->nonce);
 strcat(data, temp);

 // Include transaction data in hash
 for (int i = 0; i < block->transaction_count; i++) {
 strcat(data, block->transactions[i].sender);
 strcat(data, block->transactions[i].recipient);
 sprintf(temp, "%f", block->transactions[i].amount);
 strcat(data, temp);
 }

 // Compute SHA-256 hash
 unsigned char hash[SHA256_DIGEST_LENGTH];
 SHA256((unsigned char*)data, strlen(data), hash);

 bytesToHex(hash, output_hash);
}

// Create a new block
Block* create_block(int index, Transaction* transactions, int tx_count, 
 const char* previous_hash) {
 Block* new_block = (Block*)malloc(sizeof(Block));

 new_block->index = index;
 new_block->timestamp = time(NULL);
 new_block->transaction_count = tx_count;
 memcpy(new_block->transactions, transactions, tx_count * sizeof(Transaction));
 strcpy(new_block->previous_hash, previous_hash);
 new_block->nonce = 0;
 new_block->next = NULL;

 calculate_block_hash(new_block, new_block->hash);

 return new_block;
}

// Proof of Work - mine the block (find nonce with correct hash)
void mine_block(Block* block, int difficulty) {
 char target[HASH_SIZE];
 memset(target, '0', difficulty);
 target[difficulty] = '\0';

 printf("Mining Block #%d... ", block->index);
 fflush(stdout);

 // Keep incrementing nonce until hash starts with required zeros
 while (strncmp(block->hash, target, difficulty) != 0) {
 block->nonce++;
 calculate_block_hash(block, block->hash);
 }

 printf("Mined! Nonce: %u, Hash: %.16s...\n", block->nonce, block->hash);
}

// Create genesis block (first block in blockchain)
Blockchain* create_blockchain() {
 Blockchain* chain = (Blockchain*)malloc(sizeof(Blockchain));
 chain->difficulty = 3;

 // Create genesis block
 Transaction genesis_tx = {"SYSTEM", "Genesis", 0.0};
 Block* genesis = create_block(0, &genesis_tx, 1, "0");
 mine_block(genesis, chain->difficulty);

 chain->genesis_block = genesis;
 chain->last_block = genesis;

 return chain;
}

// Add new block to blockchain
void add_block(Blockchain* chain, Transaction* transactions, int tx_count) {
 Block* new_block = create_block(
 chain->last_block->index + 1,
 transactions,
 tx_count,
 chain->last_block->hash
 );

 mine_block(new_block, chain->difficulty);

 chain->last_block->next = new_block;
 chain->last_block = new_block;
}

// Validate blockchain integrity
int validate_blockchain(Blockchain* chain) {
 Block* current = chain->genesis_block->next;
 Block* previous = chain->genesis_block;

 while (current != NULL) {
 // Check if previous hash matches
 if (strcmp(current->previous_hash, previous->hash) != 0) {
 printf("Error: Block #%d previous hash mismatch!\n", current->index);
 return 0;
 }

 // Verify hash recalculation
 char calculated_hash[HASH_SIZE];
 calculate_block_hash(current, calculated_hash);

 if (strcmp(current->hash, calculated_hash) != 0) {
 printf("Error: Block #%d has been tampered!\n", current->index);
 return 0;
 }

 previous = current;
 current = current->next;
 }

 return 1;
}

// Print blockchain
void print_blockchain(Blockchain* chain) {
 Block* current = chain->genesis_block;

 while (current != NULL) {
 printf("\n=== Block #%d ===\n", current->index);
 printf("Timestamp: %s", ctime(&current->timestamp));
 printf("Transactions: %d\n", current->transaction_count);
 printf("Previous Hash: %.16s...\n", current->previous_hash);
 printf("Hash: %.16s...\n", current->hash);
 printf("Nonce: %u\n", current->nonce);

 current = current->next;
 }
}

// Demonstrate digital signature concept (asymmetric cryptography)
void demonstrate_digital_signature() {
 printf("\n=== Digital Signature Demonstration ===\n");
 printf("In blockchain, digital signatures use public-key cryptography:\n");
 printf("1. Private Key: Kept SECRET by the owner\n");
 printf("2. Public Key: Shared freely (wallet address)\n");
 printf("3. Signature: Created using private key to authorize transactions\n");
 printf("4. Verification: Anyone can verify using public key\n");
 printf("This ensures authentication and non-repudiation.\n");
}

// Main function
int main() {
 printf("=== Blockchain Generic Elements Demo ===\n");

 // Create blockchain
 Blockchain* chain = create_blockchain();

 // Add transactions
 Transaction tx1 = {"Alice", "Bob", 10.0};
 Transaction tx2 = {"Bob", "Charlie", 5.0};
 add_block(chain, &tx1, 1);

 Transaction tx3 = {"Charlie", "Alice", 3.0};
 Transaction tx4 = {"Alice", "David", 7.0};
 add_block(chain, &tx3, 2);

 // Print blockchain
 print_blockchain(chain);

 // Validate
 printf("\nBlockchain valid: %s\n", validate_blockchain(chain) ? "YES" : "NO");

 // Demonstrate digital signatures
 demonstrate_digital_signature();

 return 0;
}
